mapper.select:
SELECT COUNT(1)
FROM twin_dahua_activation_state
WHERE task_id = #{taskId}
  AND user_id = #{userId}
  AND last_record_id = #{recordId}

SELECT COUNT(1)
FROM twin_dahua_swing_record
WHERE 1 = 1
AND task_id = #{taskId}
AND channel_code = #{channelCode}
AND person_code = #{personCode}
AND person_name LIKE CONCAT('%', #{personName}, '%')
AND open_type = #{openType}
AND swing_time >= #{startTime}
AND swing_time <= #{endTime}

mapper.delete:
DELETE FROM twin_dahua_activation_state
WHERE task_id = #{taskId}
  AND user_id = #{userId}
  AND channel_code = #{channelCode}

